(* :Summary:

 * This package contains various functions for interfacing with

 * the PsiEv external program.

 *)



BeginPackage["Quantum`Psi`"]



Unprotect[SetOptions]



StartPsiEv::usage=

	"StartPsiEv[] starts the external program PsiEv."



QuitPsiEv::usage=

	"QuitPsiEv[] frees the memory used by PsiEv and terminates it."



AnimatePsi::usage=

	"AnimatePsi[t, dt] produces a sequence of graphical frames representing

	the state of the system 

	as the wavefunction is evolved forward in time by a time-interval t

	in steps of dt starting with the current state. Depending on the settings of

	the options RecordProbabilities and RecordPsi, it may also record the data of the

	probabilities and values of the wavefunction at each frame after discarding

	previously recorded data. AnimatePsi[t, dt, NewExpt->False] starts with

	the next state and does not discard previous data.

	AnimatePsi[] continues the previous AnimatePsi command."



ShowCurrentState::usage=

	"ShowCurrentState[] produces a graphic representing the current state of the

	system."



ShowProbabilities::usage=

	"ShowProbabilities[] displays the recorded probability data."



SetHarmOscPotential::usage=

	"SetHarmOscPotential[x0, k] sets the potential function to be that for a 

	classical simple harmonic oscillator with mean position x0 and force constant k."



PeriodSHO::usage=

	"PeriodSHO[m, k] calculates the period for a classical simple harmonic

	oscillator of mass m and spring constant k."



RStep::usage=

	"RStep[Textbook, e, v0] gives the reflection coefficient for a particle

	of energy e incident on a potential step of height v0.

	RStep[PlaneWave, p, v0] does the same for a particle of momentum p.

	RStep[General, f, {p, p1, p2}, v0] does likewise for a wavepacket with

	momentum spectral function f with momentum components in the range p1 to p2.

	RStep[Gaussian, p0, sp, v0] acts similarly for a Gaussian wavepacket

	with mean momentum p0 and momentum standard deviation sp."



RBarrier::usage=

	"RBarrier[Textbook, e, v0, a] gives the reflection coefficient for a particle

	of energy e incident on a potential step of height v0.

	RBarrier[PlaneWave, p, v0, a] does the same for a particle of momentum p.

	RBarrier[General, f, {p, p1, p2}, v0, a] does likewise for a wavepacket with

	momentum spectral function f with momentum components in the range p1 to p2.

	RBarrier[Gaussian, p0, sp, v0, a] acts similarly for a Gaussian wavepacket

	with mean momentum p0 and momentum standard deviation sp."



PlotStyleRe::usage=PlotStyleIm::usage=PlotStyleAbSq::usage=PlotStylePotential::usage=

	PlotStyleEnergy::usage=

	"PlotStyleX where X = Re, Im, AbSq, Potential or Energy are options

	for the Quantum`Psi` package.

	PlotStyleX -> style specifies that the real, imaginary, absolute square,

	potential or energy values

	are to be generated with the specified graphics directive or list of directives."



DisplayRe::usage=DisplayIm::usage=DisplayAbSq::usage=DisplayPotential::usage=

	DisplayEnergy::usage=

	"DisplayX where X = Re, Im, AbSq, Potential or Energy are options for the

	Quantum`Psi` package.

	With DisplayX -> True, the real, imaginary, absolute square, potential

	or energy values are automatically plotted. With DisplayX -> False they are not."



JM::usage=

	"JM is an option for the Quantum`Psi` package. JM+1 is the number of points

	used to produce the graphics representing the quantum mechanical system."



RecordPsi::usage=RecordProbabilities::usage=

	"RecordPsi and RecordProbabilities are options for the Quantum`Psi` package.

	With RecordPsi -> True or RecordProbabilities -> True, the values

	of the wavefunction at each frame generated by AnimatePsi are stored 

	in the variables PsiList and ProbList. With RecordPsi -> False or

	RecordProbabilities -> False, they are not."



XBoundaries::usage=

	"XBoundaries is an option for the Quantum`Psi` package.

	If RecordProbabilities -> True, XBoundaries -> {x1, x2, x3, ...}

	will record the values of the integral of the absolute square of the

	wavefunction over the ranges x1..x2, x2..x3, ..."



PlotMin::usage=PlotMax::usage=

	"PlotMin and PlotMax are options for the Quantum`Psi` package.

	With PlotMin -> pmin and PlotMax -> pmax, the plot range used in producing

	the graphics is {pmin, pmax}."



PotentialScale::usage=

	"PotentialScale is an option for the Quantum`Psi` package.

	PotentialScale -> Automatic chooses the scale for plotting the potential

	automatically. PotentialScale -> preal scales the potential function

	by a factor preal."



NewExpt::usage=

	"NewExpt is an option for AnimatePsi. NewExpt -> False does not discard

	previously stored data and does not plot the current state. NewExpt -> True

	does the opposite."



ProbStyles::usage=

	"ProbStyles is an option for ShowProbabilities. ProbStyles -> Automatic

	uses a predefined style scheme for the plots. ProbStyle -> {style1, style2, ...}

	uses style1 for the first plot, style2 for the next plot, ..."



Energy::usage=

	"Energy is an option for the Quantum`Psi` package. Energy -> e specifies an

	arbitrary energy value e intended for display along with the potential function

	in order to facilitate easy visual comparison."



HBar::usage=

	"HBar is an option for RTCalculations. It sets the value of the rationalized

	Planck's constant used by RStep and RBarrier.

	It has no effect on PsiEv which always uses 1."



Mass::usage=

	"Mass is an option for RTCalculations. It sets the value of the mass used

	by RStep and RBarrier. It has no effect on PsiEv which always uses 1/2."



Textbook::usage=

	"Textbook is an parameter for RStep and RBarrier. It specifies that

	the incident particle is represented by a momentum eigenfunction."



PlaneWave::usage=

	"PlaneWave is a parameter for RStep and RBarrier. It specifies that

	the incident particle is represented by a momentum eigenfunction."



General::usage=

	"General is a parameter for RStep and RBarrier. It specifies that

	the incident particle is represented by a general wavefunction comprised

	of a spread of momenta."



Gaussian::usage=

	"Gaussian is a parameter for RStep and RBarrier. It specifies that

	the incident particle is represented by a Gaussian wavepacket."



Options[QuantumPsi]={}



SetOptions[QuantumPsi,QuantumPsi`Private`opts]:={}



Options[ShowProbabilities]={}



SetOptions[ShowProbabilities,QuantumPsi`Private`opts]:={}



Options[RTCalculations]={}



SetOptions[RTCalculations,QuantumPsi`Private`opts]:={}



Begin["`Private`"]



StartPsiEv[]:=

	Module[

		{},

		PsiEvLink=Install["c:\\al\\bc4\\math\\psiev"];

		Quantum`Psi`Init[]

	]

StartPsiEv[]



QuitPsiEv[]:=

	Module[

		{},

		Done[];

		Uninstall[PsiEvLink]

	]



PsiList=ProbList=XBoundariesList={}



OldAPParmsList={0,1,{}}



(* Initialize options to their default values *)

Options[QuantumPsi]=

	{PlotStyleRe->RGBColor[1,0,0],PlotStyleIm->RGBColor[0,0,1],

	PlotStyleAbSq->RGBColor[0,0,0],

	PlotStylePotential->RGBColor[0,0.7,0],

	PlotStyleEnergy->{RGBColor[0,0.8,0.8],Dashing[{0.02,0.01}]},

	DisplayRe->False,DisplayIm->False,DisplayAbSq->True,

	DisplayPotential->True,DisplayEnergy->False,Energy->0,

	JM->100,RecordPsi->False,RecordProbabilities->True,

	XBoundaries->{0,GetParms[][[3]]},PlotMin->0,PlotMax->10,

	PotentialScale->Automatic,NewExpt->True,PlotJoined->True,

	Ticks->{Automatic,None},Axes->{True,False}}



SetOptions[QuantumPsi,opts___]:=

	Options[QuantumPsi]=

		MakeOptionsList[QuantumPsi, Join[{opts},Options[QuantumPsi]]]



Options[ShowProbabilities]=

	{ProbStyles->Automatic,PlotJoined->True}



SetOptions[ShowProbabillities,opts___]:=

	Options[ShowProbabilities]=

		MakeOptionsList[ShowProbabilities,

			Join[{opts},Options[ShowProbabilities]]]



MakePotPlot[xList_,jm_,plotrange_,lpopts_,opts___]:=

	Module[

		{vList,vmin,vmax,vscale,dispenergy,plotstyleenergy,energy,eplot={}},

		vList=GetPotential[jm];

		dispenergy=DisplayEnergy/.{opts}/.Options[QuantumPsi];

		If[

			Automatic==PotentialScale/.{opts}/.Options[QuantumPsi],

			vmin=Min[vList];

			vmax=Max[vList];

			If[dispenergy,

				{plotstyleenergy,energy}=

					{PlotStyleEnergy,Energy}/.{opts}/.Options[QuantumPsi];

				vmin=Min[vmin,energy];

				vmax=Max[vmax,energy];

			];

			If[plotrange[[1]]==0,

				If[plotrange[[2]]==0,

					vscale=0,

					If[vmax==0,

						vscale=0,

						vscale=Abs[plotrange[[2]]/vmax]]

				],

				If[plotrange[[2]]==0,

					If[vmin==0,

						vscale=0,

						vscale=Abs[plotrange[[1]]/vmin]],

					If[vmin==0,

						If[vmax==0,

							vscale=0,

							vscale=Abs[plotrange[[2]]/vmax]],

						If[vmax==0,

							vscale=Abs[plotrange[[1]]/vmin],

							vscale=Min[

								Abs[{plotrange[[2]]/vmax,

									plotrange[[1]]/vmin}]]]

					]

				]

			],

			vscale=PotentialScale/.{opts}/.Options[QuantumPsi]

		];

		If[dispenergy/.{opts}/.Options[QuantumPsi],

			energy*=vscale;

			eplot=

				Graphics[

					If[Head[plotstyleenergy]==List,

						Flatten[{plotstyleenergy,

						Line[{{0,energy},{GetParms[][[3]],energy}}]}],

						{plotstyleenergy,

						Line[{{0,energy},{GetParms[][[3]],energy}}]}

					]

				]

		];

		Show[

			ListPlot[Transpose[{xList,vList vscale}],

				PlotStyle->(PlotStylePotential/.{opts}/.Options[QuantumPsi]),

				DisplayFunction->Identity,

				lpopts],

			eplot,DisplayFunction->Identity]

	]



MakePsiPlots[xList_,jm_,dispre_,dispim_,dispabsq_,lpopts_,opts___]:=

	Module[

		{psiplotlist={}},

		If[

			dispre,

			AppendTo[psiplotlist,

				ListPlot[

					Transpose[{xList,Re[GetPsi[jm]]}],

					PlotStyle->(PlotStyleRe/.{opts}/.Options[QuantumPsi]),

					DisplayFunction->Identity,

					lpopts

				]

			]

		];

		If[

			dispim,

			AppendTo[psiplotlist,

				ListPlot[

					Transpose[{xList,Im[GetPsi[jm]]}],

					PlotStyle->(PlotStyleIm/.{opts}/.Options[QuantumPsi]),

					DisplayFunction->Identity,

					lpopts

				]

			]

		];

		If[

			dispabsq,

			AppendTo[psiplotlist,

				ListPlot[

					Transpose[{xList,GetProbDensity[jm]}],

					PlotStyle->(PlotStyleAbSq/.{opts}/.Options[QuantumPsi]),

					DisplayFunction->Identity,

					lpopts

				]

			]

		];

		psiplotlist

	]



RecordData[currenttime_,jm_,recpsi_,recprob_,opts___]:=

	Module[

		{},

		If[recpsi,

			AppendTo[PsiList,

				{currenttime,GetPsi[jm]}

			]

		];

		If[recprob,

			AppendTo[ProbList,

				{currenttime,Table[GetProbability[XBoundariesList[[n]],

					XBoundariesList[[n+1]]],{n, Length[XBoundariesList]-1}]}

			]

		]

	]



AnimatePsi[t_,dt_,opts___]/;t>=0/;dt>=0:=

	Module[

		{graflist={},time},

		If[NewExpt/.{opts}/.Options[QuantumPsi],

			PsiList=ProbList={};

			XBoundariesList=XBoundaries/.{opts}/.Options[QuantumPsi];

			RecordData[GetTime[],JM,RecordPsi,

				RecordProbabilities,opts]/.{opts}/.Options[QuantumPsi];

			graflist={ShowCurrentState[opts]};

			OldAPParmsList={t,dt,{opts}}

		];

		Join[graflist,RunSim[t,dt,opts]]

	]



AnimatePsi[]:=

	Module[

		{t,dt,oldopts},

		{t,dt,oldopts}=OldAPParmsList;

		AnimatePsi[t,dt,Sequence @@ Join[{NewExpt->False},oldopts]]

	]



MakeOptionsList[sym_,optslist___]:=

	Module[

		{tmp},

		tmp=Options[sym];

		tmp=Table[tmp[[n,1]],{n,Length[tmp]}];

		tmp=Transpose[{tmp,

			(tmp/.optslist/.Options[sym])}];

		Table[Apply[Rule,tmp[[n]]],{n,Length[tmp]}]

	]



ShowCurrentState[opts___]:=

	Module[

		{w,jm,dispre,dispim,dispabsq,disppot,displayfunction,

		plotrange,xList,vplot,lpopts},

		w=GetParms[][[3]];

		{jm,dispre,dispim,dispabsq,disppot,displayfunction,plotrange}=

			{JM,DisplayRe,DisplayIm,DisplayAbSq,DisplayPotential,DisplayFunction,

			{PlotMin,PlotMax}}/.

			{opts}/.Options[QuantumPsi]/.Options[ListPlot];

		lpopts=MakeOptionsList[ListPlot,Join[{opts},Options[QuantumPsi]]];

		xList=Table[x,{x,0,w,w/jm}];

		If[disppot,vplot=MakePotPlot[xList,jm,plotrange,lpopts,opts]];

		Show[

			vplot,

			MakePsiPlots[xList,jm,dispre,dispim,dispabsq,lpopts,opts],

			Graphics[

				Table[

					Line[Table[{u,plotrange[[v]]},{v,1,2}]],

					{u,0,w,w}

				]

			],

			PlotRange->plotrange,

			DisplayFunction->displayfunction,

			PlotLabel->"t = "<>ToString[GetTime[]//N],

			Evaluate[MakeOptionsList[Graphics,Join[{opts},Options[QuantumPsi]]]]

		]

	]



RunSim[t_,dt_,opts___]/;t>=0/;dt>0:=

	Module[

		{w,jm,dispre,dispim,dispabsq,disppot,xList,displayfunction,plotrange,

		vplot={},currenttime,time,lpopts,recpsi,recprob},

		w=GetParms[][[3]];

		{jm,dispre,dispim,dispabsq,disppot,displayfunction,plotrange,recpsi,recprob}=

			{JM,DisplayRe,DisplayIm,DisplayAbSq,DisplayPotential,

			DisplayFunction,{PlotMin,PlotMax},RecordPsi,

			RecordProbabilities}/.{opts}/.Options[QuantumPsi]/.Options[ListPlot];

		lpopts=MakeOptionsList[ListPlot,Join[{opts},Options[QuantumPsi]]];

		xList=Table[x,{x,0,w,w/jm}];

		If[disppot,vplot=MakePotPlot[xList,jm,plotrange,lpopts,opts]];

		Table[

			currenttime=Evolve[dt]//N;

			RecordData[currenttime,jm,recpsi,

				recprob,opts];

			Show[

				vplot,

				MakePsiPlots[xList,jm,dispre,dispim,dispabsq,lpopts,opts],

				Graphics[

					Table[

						Line[Table[{u,plotrange[[v]]},{v,1,2}]],

						{u,0,w,w}

					]

				],

				PlotRange->plotrange,

				DisplayFunction->displayfunction,

				PlotLabel->"t = "<>ToString[currenttime],

				Evaluate[MakeOptionsList[Graphics,Join[{opts},Options[QuantumPsi]]]]

			],

			{time,dt,t,dt}

		]

	]



ShowProbabilities[opts___]:=

	Module[

		{lpopts,b,n,plotlist,defcolorlist,autostyle=False},

		defcolorlist=

			Drop[

				Flatten[

					Table[RGBColor[x,y,z],{x,1,0,-1},{y,1,0,-1},{z,1,0,-1}]],1];

		probstyles=(ProbStyles/.{opts}/.Options[ShowProbabilities]);

		If[probstyles==Automatic, autostyle=True];

		lpopts=MakeOptionsList[ListPlot,Join[{opts},Options[ShowProbabilities]]];

		plotlist=Table[

			ListPlot[

				Table[

					{ProbList[[n,1]],ProbList[[n,2,b]]},

					{n,Length[ProbList]}

				],

				PlotLabel->

					"P ["<>ToString[XBoundariesList[[b]]]<>" < x < "<>

					ToString[XBoundariesList[[b+1]]]<>"]",

				AxesLabel->{"t","P"},

				PlotStyle->

					If[autostyle,

						defcolorlist[[1+Mod[b,Length[defcolorlist]]]],

						probstyles[[1+Mod[b,Length[probstyles]]]]],

				lpopts

			],

			{b,Length[XBoundariesList]-1}

		];

		AppendTo[plotlist, Show[plotlist, PlotLabel->"All"]]

	]



SetHarmOscPotential[x0_,k_]:=

	Module[

		{jp,l,w,t},

		{jp,l,w,t}=GetParms[];

		SetPotential[Table[k(x-x0)^2/2,{x,0,w,w/jp}]]

	]



PeriodSHO[m_,k_]:=

	2Pi Sqrt[m/k]



Options[RTCalculations]={Mass->1/2,HBar->1}



SetOptions[RTCalculations,opts___]:=

	Options[RTCalculations]=

		MakeOptionsList[RTCalculations,Join[{opts},Options[RTCalculations]]]



RStep[Textbook,0,___]=1



RStep[Textbook,e_,v0_,___]=

	Abs[(1-Sqrt[1-v0/e])/(1+Sqrt[1-v0/e])]^2



RStep[PlaneWave,p_,v0_,opts___]:=

	RStep[Textbook,p^2/(2Mass),v0]/.{opts}/.Options[RTCalculations]



RStep[General,f_,{p_,p1_,p2_},v0_,opts___]:=

	NIntegrate[f^2 RStep[Textbook,p^2/(2Mass),v0],

		{p,p1,p2}]/NIntegrate[f^2,{p,p1,p2}]/.{opts}/.Options[RTCalculations]



RStep[Gaussian,p0_,sp_,v0_,opts___]:=

	Module[

		{p,f},

		f=Exp[-((p-p0)/sp)^2/2] RStep[Textbook,p^2/(2Mass),v0]

			/.{opts}/.Options[RTCalculations];

		(NIntegrate[f,{p,0,Sqrt[v0]}]+

		NIntegrate[f,{p,Sqrt[v0],Infinity}])/(sp Sqrt[2Pi])

	]



RBarrier[Textbook,0,___]=1



RBarrier[Textbook,e_,v0_,a_,opts___]/;e==v0:=

	1/(1+2 HBar^2/(v0 Mass a^2))/.{opts}/.Options[RTCalculations]



RBarrier[Textbook,e_,v0_,a_,opts___]:=

	1/Abs[(1+4 e(e-v0)/(v0 Sin[Sqrt[2 Mass (e-v0)] a/HBar])^2)]/.

		{opts}/.Options[RTCalculations]



RBarrier[PlaneWave,p_,v0_,a_,opts___]:=

	RBarrier[Textbook,p^2/(2Mass),v0,a]/.{opts}/.Options[RTCalculations]



RBarrier[General,f_,{p_,p1_,p2_},v0_,a_,opts___]:=

	NIntegrate[f^2 RBarrier[Textbook, p^2/(2Mass),v0,a,opts],

		{p,p1,p2}]/NIntegrate[f^2,{p,p1,p2}]/.{opts}/.Options[RTCalculations]



RBarrier[Gaussian,p0_,sp_,v0_,a_,opts___]:=

	Module[

		{p,f},

		f=Exp[-((p-p0)/sp)^2/2] RBarrier[Textbook,p^2/(2Mass),v0,a,opts]

			/.{opts}/.Options[RTCalculations];

		(NIntegrate[f,{p,0,Sqrt[v0]}]+

		NIntegrate[f,{p,Sqrt[v0],Infinity}])/(sp Sqrt[2Pi])

	]



End[] (* Quantum`Psi`Private` *)



Protect[SetOptions]



EndPackage[] (* Quantum`Psi` *)











